// IKSASS - docs.js (documents listing with categories + search)
(function () {
  const utils = window.IKSASS || {};
  const toRootUrl = utils.toRootUrl || ((value) => String(value || ''));
  const escapeHtml = utils.escapeHtml || ((value) => String(value || ''));
  const normalizeText = utils.normalizeText || ((value) => String(value || '').toLowerCase());
  const safeISODate = utils.safeISODate || ((value) => (/^\d{4}-\d{2}-\d{2}$/.test(String(value || '').trim()) ? String(value || '').trim() : ''));

  const els = {
    chips: document.getElementById('docsChips'),
    search: document.getElementById('docsSearchInput'),
    list: document.getElementById('docsList'),
    empty: document.getElementById('docsEmpty'),
    featured: document.getElementById('docsFeatured'),
  };

  if (!els.chips || !els.search || !els.list) return;

  const state = {
    data: null,
    q: '',
    category: 'ALL',
  };

  function byDateDesc(a, b) {
    return (safeISODate(b.date_iso) || '1970-01-01').localeCompare(safeISODate(a.date_iso) || '1970-01-01');
  }

  function buildDocRow(item) {
    const metaParts = [];
    if (item.category) metaParts.push(escapeHtml(item.category));
    if (item.date_display && item.date_display !== '—') metaParts.push(escapeHtml(item.date_display));
    const meta = metaParts.join(' • ') || 'PDF';
    const file = String(item.file || '').trim();
    const href = file ? toRootUrl(`assets/files/dokumen/${file}`) : '';
    const desc = item.description ? `<div class="docs-desc">${escapeHtml(item.description)}</div>` : '';

    return `
      <div class="list">
        <div class="row">
          <div>
            <div><b>${escapeHtml(item.title)}</b></div>
            <div class="meta">${meta}</div>
            ${desc}
          </div>
          <div class="doc-actions">
            <a class="small-link" href="${href}" rel="noopener" target="_blank">Buka</a>
            <a class="small-link" href="${href}" download>Unduh</a>
          </div>
        </div>
      </div>
    `;
  }

  function groupByCategory(items, order) {
    const grouped = new Map();
    items.forEach((item) => {
      const category = (item.category || 'Lainnya').trim() || 'Lainnya';
      if (!grouped.has(category)) grouped.set(category, []);
      grouped.get(category).push(item);
    });

    const output = [];
    (order || []).forEach((category) => {
      if (grouped.has(category)) output.push([category, grouped.get(category)]);
    });
    Array.from(grouped.keys()).sort().forEach((category) => {
      if (!(order || []).includes(category)) output.push([category, grouped.get(category)]);
    });
    return output;
  }

  function applyChipInlineStyles() {
    els.chips.querySelectorAll('.docs-chip').forEach((btn) => {
      const active = btn.classList.contains('docs-chip--active') || (btn.getAttribute('data-cat') || '') === state.category;
      const label = btn.querySelector('.docs-chip-label');
      const count = btn.querySelector('.docs-chip-count');
      btn.setAttribute(
        'style',
        active
          ? 'background:var(--theme-green,#5f7f2b);color:#fff;border:1px solid var(--theme-green,#5f7f2b);opacity:1;-webkit-text-fill-color:#fff;'
          : 'background:var(--theme-green-soft,#eef4e6);color:var(--theme-text,#3f5f18);border:1px solid var(--theme-border,#d6e4c2);opacity:1;-webkit-text-fill-color:var(--theme-text,#3f5f18);',
      );
      btn.setAttribute('aria-current', active ? 'page' : 'false');
      if (label) {
        label.setAttribute(
          'style',
          active
            ? 'color:#fff;opacity:1;visibility:visible;-webkit-text-fill-color:#fff;font-weight:600;'
            : 'color:var(--theme-text,#3f5f18);opacity:1;visibility:visible;-webkit-text-fill-color:var(--theme-text,#3f5f18);font-weight:500;',
        );
      }
      if (count) count.setAttribute('style', 'background:var(--theme-green,#5f7f2b);color:#fff;opacity:1;visibility:visible;-webkit-text-fill-color:#fff;');
    });
  }

  function renderChips(items, order) {
    const counts = new Map();
    items.forEach((item) => {
      const category = (item.category || 'Lainnya').trim() || 'Lainnya';
      counts.set(category, (counts.get(category) || 0) + 1);
    });

    const cats = [];
    (order || []).forEach((category) => { if (counts.has(category)) cats.push(category); });
    Array.from(counts.keys()).sort().forEach((category) => {
      if (!(order || []).includes(category)) cats.push(category);
    });

    function chipButton(label, value, count) {
      const active = state.category === value;
      const className = active ? ' docs-chip--active' : '';
      const btnStyle = active
        ? 'background:linear-gradient(180deg,var(--brand-800,#4E6A24),var(--brand-500,#6F8F3A));color:#F8FAF7;border-color:transparent;opacity:1;-webkit-text-fill-color:#F8FAF7;'
        : 'background:#fff;color:var(--iksass-header-dark,#4E6A24);border:1px solid rgba(111,143,58,.26);opacity:1;-webkit-text-fill-color:var(--iksass-header-dark,#4E6A24);';
      const labelStyle = active
        ? 'color:#F8FAF7;opacity:1;-webkit-text-fill-color:#F8FAF7;'
        : 'color:var(--iksass-header-dark,#4E6A24);opacity:1;-webkit-text-fill-color:var(--iksass-header-dark,#4E6A24);';
      const counter = typeof count === 'number' ? `<span class="docs-chip-count">${count}</span>` : '';
      return `<button type="button" class="docs-chip${className}" data-cat="${escapeHtml(value)}" style="${btnStyle}"><span class="docs-chip-label" style="${labelStyle}">${escapeHtml(label)}</span>${counter}</button>`;
    }

    els.chips.innerHTML = chipButton('Semua', 'ALL', items.length) + cats.map((category) => chipButton(category, category, counts.get(category) || 0)).join('');
    applyChipInlineStyles();

    els.chips.querySelectorAll('button[data-cat]').forEach((btn) => {
      btn.addEventListener('click', () => {
        state.category = btn.getAttribute('data-cat') || 'ALL';
        render();
        els.chips.querySelectorAll('.docs-chip').forEach((chip) => chip.classList.remove('docs-chip--active'));
        btn.classList.add('docs-chip--active');
        applyChipInlineStyles();
      });
    });
  }

  function renderFeatured(items) {
    if (!els.featured) return;
    const featured = items.filter((item) => !!item.featured).sort(byDateDesc);
    if (!featured.length) {
      els.featured.hidden = true;
      els.featured.innerHTML = '';
      return;
    }

    els.featured.hidden = false;
    els.featured.innerHTML = `<div class="docs-section-title">Unggulan</div>${featured.map(buildDocRow).join('')}`;
  }

  function render() {
    const allItems = (state.data?.items || []).slice().sort(byDateDesc);
    const isFiltering = state.category !== 'ALL' || !!state.q;
    if (!isFiltering) renderFeatured(allItems);
    else if (els.featured) {
      els.featured.hidden = true;
      els.featured.innerHTML = '';
    }

    const items = allItems.filter((item) => {
      const category = (item.category || 'Lainnya').trim() || 'Lainnya';
      if (state.category !== 'ALL' && category !== state.category) return false;
      if (!state.q) return true;
      const haystack = normalizeText(item.title) + ' ' + normalizeText(item.description) + ' ' + normalizeText(category);
      return haystack.includes(normalizeText(state.q));
    });

    if (!items.length) {
      els.list.innerHTML = '';
      if (els.empty) els.empty.hidden = false;
      return;
    }

    if (els.empty) els.empty.hidden = true;
    const grouped = groupByCategory(items, state.data?.categories_order || []);
    els.list.innerHTML = grouped.map(([category, arr]) => {
      const heading = state.category === 'ALL' ? `<h3 class="docs-cat">${escapeHtml(category)}</h3>` : '';
      return `${heading}${arr.sort(byDateDesc).map(buildDocRow).join('')}`;
    }).join('');
  }

  function init() {
    fetch('docs-index.json', { cache: 'no-store' })
      .then((response) => (response.ok ? response.json() : Promise.reject(new Error('docs-index fetch failed'))))
      .then((data) => {
        state.data = data || { items: [] };
        const items = (state.data.items || []).slice();
        renderChips(items, state.data.categories_order || []);
        render();
        applyChipInlineStyles();
      })
      .catch((error) => {
        console.warn('[docs] gagal memuat data dokumen', error);
      });

    els.search.addEventListener('input', (event) => {
      state.q = event.target.value || '';
      render();
    });
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
  else init();
})();
